  for (let r = 0; r < 9; r++) {
    for (let c = 0; c < 9; c++) {
      const val = board[r][c];
      if (val === ".") continue;
      const boxIdx = `${Math.floor(r / 3)}-${Math.floor(c / 3)}`;
      if ((rows[r] && rows[r][val]) || (cols[c] && cols[c][val]) || (boxes[boxIdx] && boxes[boxIdx][val])) {
